protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex removed: EF Core 9 Cosmos throws at startup. Manage
    // indexing policy via Azure Portal / Bicep / Terraform instead.

    modelBuilder.Entity<Product>().ToContainer("Products");

    // Preserve EF Core 8 discriminator property name ("Discriminator")
    // so existing 500K documents remain queryable.
    // EF Core 9 default changed to "$type".
    modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

    // Preserve EF Core 8 compound id format ("Product|123")
    // so FindAsync and point-reads work against existing documents.
    // EF Core 9 default changed to key-only ("123").
    modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);
}

