using System.Linq;

class CosmosQuery
{
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — "Discriminator" property preserved via
        // HasDiscriminator("Discriminator") in OnModelCreating.
        // Without that config EF Core 9 would write "$type" instead,
        // breaking this query against existing documents.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 Cosmos no longer supports sync I/O — use async.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

